// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SupportTicketAttachment) predicate.SupportTicketAttachment {
	return predicate.SupportTicketAttachment(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SupportTicketAttachment) predicate.SupportTicketAttachment {
	return predicate.SupportTicketAttachment(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SupportTicketAttachment) predicate.SupportTicketAttachment {
	return predicate.SupportTicketAttachment(sql.NotPredicates(p))
}
